```javascript
#!/usr/bin/env node
const { Project, SyntaxKind } = require('ts-morph');

// This script safely transforms object spread syntax into Object.assign calls
// using the TypeScript Compiler API via ts-morph. This avoids the pitfalls
// of regex-based transformations by understanding the code's structure (AST).
async function run() {
  const project = new Project();
  project.addSourceFilesAtPaths('packages/**/*.ts');

  const sourceFiles = project.getSourceFiles();
  let changedFiles = 0;

  console.log(`Analyzing ${sourceFiles.length} source files for object spreads...`);

  for (const sourceFile of sourceFiles) {
    let madeChangesInFile = false;

    // We must traverse in reverse (bottom-up) to safely replace nodes.
    // Replacing a node invalidates its children, so if we go top-down,
    // we would be operating on stale node references after the first replacement.
    const objectLiterals = sourceFile.getDescendantsOfKind(SyntaxKind.ObjectLiteralExpression);
    for (const objectLiteral of [...objectLiterals].reverse()) {
      const properties = objectLiteral.getProperties();
      const spreadAssignments = properties.filter(p => p.isKind(SyntaxKind.SpreadAssignment));

      if (spreadAssignments.length === 0) {
        continue; // This object literal doesn't use spread, skip it.
      }

      madeChangesInFile = true;

      const regularProperties = properties.filter(p => !p.isKind(SyntaxKind.SpreadAssignment));
      const spreadExpressions = spreadAssignments.map(p => p.getExpression().getText());

      let replacementText;

      if (regularProperties.length > 0) {
        // Has both regular properties and spreads. e.g., { a: 1, ...b, c: 2 }
        // Transforms to: Object.assign({ a: 1, c: 2 }, b)
        const regularPropsText = regularProperties.map(p => p.getText()).join(', ');
        replacementText = `Object.assign({ ${regularPropsText} }, ${spreadExpressions.join(', ')})`;
      } else {
        // Only has spreads. e.g., { ...a, ...b }
        // Transforms to: Object.assign({}, a, b)
        replacementText = `Object.assign({}, ${spreadExpressions.join(', ')})`;
      }

      try {
        objectLiteral.replaceWithText(replacementText);
      } catch (e) {
        console.error(`[Error] Failed to replace node in ${sourceFile.getFilePath()} at line ${objectLiteral.getStartLineNumber()}: ${e.message}`);
        console.error(`  Original Text: ${objectLiteral.getText()}`);
      }
    }

    if (madeChangesInFile) {
      changedFiles++;
      console.log(`Applying fixes to ${sourceFile.getFilePath()}`);
      await sourceFile.save();
    }
  }

  if (changedFiles > 0) {
    console.log(`\nSuccessfully fixed object spreads in ${changedFiles} files.`);
  } else {
    console.log(`\nNo files with object spreads needed fixing.`);
  }
}

run().catch(err => {
  console.error('An unexpected error occurred during the script execution:', err);
  process.exit(1);
});
