/**
 * This transform finds object literals that contain only a single spread element
 * (e.g., `{ ...foo }`) and replaces them with `Object.assign({}, foo)`.
 * @param {import('jscodeshift').FileInfo} file
 * @param {import('jscodeshift').API} api
 */
export default function transformer(file, api) {
  const j = api.jscodeshift;
  const root = j(file.source);

  root
    .find(j.ObjectExpression, (node) => {
      return node.properties.length === 1 && node.properties[0].type === 'SpreadElement';
    })
    .replaceWith(path => {
      const spreadElement = path.node.properties[0];
      // Replace it with `Object.assign({}, foo)`
      return j.callExpression(
        j.memberExpression(j.identifier('Object'), j.identifier('assign')),
        [j.objectExpression([]), spreadElement.argument]
      );
    });

  return root.toSource({ quote: 'single' });
}
