const fs = require('fs');
const glob = require('glob');
const parser = require('@babel/parser');
const traverse = require('@babel/traverse').default;
const generate = require('@babel/generator').default;
const t = require('@babel/types');

// This script safely transforms object spread syntax to Object.assign() using an Abstract Syntax Tree (AST).
// It requires babel dependencies: npm install -D @babel/parser @babel/traverse @babel/generator @babel/types

glob('packages/**/*.ts', { ignore: '**/node_modules/**' }, (err, files) => {
  if (err) {
    console.error("Error finding files:", err);
    return;
  }

  files.forEach(file => {
    if (file.includes('node_modules')) return;
    const originalContent = fs.readFileSync(file, 'utf8');
    let wasModified = false;

    try {
      const ast = parser.parse(originalContent, {
        sourceType: 'module',
        plugins: ['typescript', 'jsx'], // Add jsx if you use .tsx files
      });

      traverse(ast, {
        ObjectExpression(path) {
          // Only transform object expressions that contain at least one spread element
          if (!path.node.properties.some(prop => t.isSpreadElement(prop))) {
            return;
          }

          const newArgs = [];
          let currentObjectLiterals = [];

          path.node.properties.forEach(prop => {
            if (t.isSpreadElement(prop)) {
              // If we have collected object properties, push them as a new object literal
              if (currentObjectLiterals.length > 0) {
                newArgs.push(t.objectExpression(currentObjectLiterals));
                currentObjectLiterals = [];
              }
              // Push the spread argument directly
              newArgs.push(prop.argument);
            } else {
              // Collect regular properties (Property or Method)
              currentObjectLiterals.push(prop);
            }
          });

          // Add any remaining properties at the end
          if (currentObjectLiterals.length > 0) {
            newArgs.push(t.objectExpression(currentObjectLiterals));
          }

          const call = t.callExpression(
            t.memberExpression(t.identifier('Object'), t.identifier('assign')),
            [t.objectExpression([]), ...newArgs]
          );

          path.replaceWith(call);
          wasModified = true;
        },
      });

      if (wasModified) {
        const { code } = generate(ast, {}, originalContent);
        fs.writeFileSync(file, code, 'utf8');
        console.log(`Updated spreads in ${file}`);
      }
    } catch (parseError) {
      console.error(`Could not parse ${file}:`, parseError.message);
    }
  });
});
