  // Find all ObjectExpressions that contain ONLY a SpreadElement
  // This correctly targets `{ ...foo }` but ignores `{ ...foo, bar: 1 }` and `[...foo]`
  root
    .find(j.ObjectExpression, {
      properties: (properties) =>
        properties.length === 1 && properties[0].type === 'SpreadElement',
