    .forEach((path) => {
      const spreadElement = path.node.properties[0];
      const spreadArgument = spreadElement.argument;

      // Replace the `{ ...foo }` node with `Object.assign({}, foo)`
      j(path).replaceWith(
        j.callExpression(
          j.memberExpression(j.identifier('Object'), j.identifier('assign')),
          [j.objectExpression([]), spreadArgument]
        )
      );
    });

  return root.toSource({ quote: 'single' });
};

