// A safer Task definition that avoids arbitrary code execution.
// Instead of a string script, it expects a function to execute.
export interface Task {
  id: string;
  execute: () => Promise<unknown>;
}

interface TaskHistoryEntry {
  task: { id: string };
  result: unknown;
  timestamp: number;
  status: 'success' | 'error';
  error?: unknown;
}

export class TaskPoller {
  private tasks: Task[] = [];
  private taskHistory: TaskHistoryEntry[] = [];
  private running = false;
  private poller: NodeJS.Timeout | null = null;

  constructor(
    private fetchIntervalMs: number = 1000,
    private maxHistory: number = 100
  ) {}

  public start() {
    if (this.running) {
      return;
    }
    this.running = true;
    this.poll();
  }

  public stop() {
    this.running = false;
    if (this.poller) {
      clearTimeout(this.poller);
      this.poller = null;
    }
  }

  public addTask(task: Task) {
    this.tasks.push(task);
  }

  private async poll() {
    if (!this.running) return;

    const currentTask = this.tasks.shift();
    if (currentTask) {
      try {
        // Securely execute the task via its predefined function
        const result = await currentTask.execute();
        this.recordHistory({
          task: { id: currentTask.id },
          result,
          timestamp: Date.now(),
          status: 'success',
        });
      } catch (e) {
        console.error(`Error executing task ${currentTask.id}:`, e);
        this.recordHistory({
          task: { id: currentTask.id },
          result: null,
          timestamp: Date.now(),
          status: 'error',
          error: e
        });
      }
    }

    // Schedule the next poll, ensuring the timer can be cleared on stop.
    this.poller = setTimeout(() => this.poll(), this.fetchIntervalMs);
  }

  private recordHistory(entry: TaskHistoryEntry) {
    this.taskHistory.push(entry);
    // Enforce a maximum history size to prevent memory leaks.
    if (this.taskHistory.length > this.maxHistory) {
      this.taskHistory.shift();
    }
  }
}
