// Define a type for task handlers for type safety
type TaskHandler = (payload: any) => Promise<any>;

// Redefine the Task interface to be a command object, not arbitrary code.
export interface Task {
  id: string;
  type: string; // e.g., 'sendEmail', 'processPayment'
  payload: any; // Data for the task, e.g., { to: '...', amount: 100 }
}

export class TaskPoller {
  private tasks: Task[] = [];
  private taskHistory: any[] = [];
  private running = false;
  private timeoutId: NodeJS.Timeout | null = null;

  constructor(
    // A map of predefined, safe functions to handle tasks.
    private readonly taskHandlers: Record<string, TaskHandler>,
    private readonly fetchIntervalMs: number = 1000,
    // Add a limit to the history to prevent memory leaks.
    private readonly maxHistorySize: number = 1000
  ) {}

  public start() {
    if (this.running) return;
    this.running = true;
    this.poll();
  }

  public stop() {
    this.running = false;
    if (this.timeoutId) {
      clearTimeout(this.timeoutId);
      this.timeoutId = null;
    }
  }

  public addTask(task: Task) {
    this.tasks.push(task);
  }

  private async poll() {
    if (!this.running) return;

    const currentTask = this.tasks.shift();
    if (currentTask) {
      const handler = this.taskHandlers[currentTask.type];
      if (handler) {
        try {
          const result = await handler(currentTask.payload);
          this.recordHistory(currentTask, result, null);
        } catch (error) {
          console.error(`Error executing task ${currentTask.id}:`, error);
          this.recordHistory(currentTask, null, error as Error);
        }
      } else {
        const error = new Error(`Unknown task type: ${currentTask.type}`);
        console.error(error.message);
        this.recordHistory(currentTask, null, error);
      }
    }

    this.timeoutId = setTimeout(() => this.poll(), this.fetchIntervalMs);
  }

  private recordHistory(task: Task, result: any, error: Error | null) {
    // Prevent unbounded growth of the history array.
    if (this.taskHistory.length >= this.maxHistorySize) {
      this.taskHistory.shift(); // Remove the oldest item
    }

    this.taskHistory.push({
      task,
      result,
      error: error ? { message: error.message, stack: error.stack } : null,
      timestamp: Date.now(),
      // DO NOT store `this` or other large/circular objects.
    });
  }
}
