// Define a type for registered, safe functions that can be sync or async
type SafeTaskFunction = (...args: any[]) => any | Promise<any>;

export interface Task {
  id: string;
  // Instead of an arbitrary script, we specify a registered function name and its arguments
  functionName: string;
  args?: any[];
}

export class TaskPoller {
  private tasks: Task[] = [];
  private taskHistory: any[] = [];
  private running = false;
  // A registry for safe, pre-defined functions
  private functions: Map<string, SafeTaskFunction> = new Map();
  private pollTimeout: NodeJS.Timeout | null = null;

  constructor(private fetchIntervalMs: number = 1000) {}

  public registerFunction(name: string, func: SafeTaskFunction) {
    this.functions.set(name, func);
  }

  public start() {
    if (this.running) return;
    this.running = true;
    this.poll();
  }

  public stop() {
    this.running = false;
    if (this.pollTimeout) {
      clearTimeout(this.pollTimeout);
      this.pollTimeout = null;
    }
  }

  public addTask(task: Task) {
    this.tasks.push(task);
  }

  private async poll() {
    if (!this.running) return;

    const currentTask = this.tasks.shift();
    if (currentTask) {
      const func = this.functions.get(currentTask.functionName);
      if (func) {
        try {
          // Execute the registered function safely with provided arguments
          const result = await Promise.resolve(func(...(currentTask.args || [])));

          // Storing a clean record without circular references
          this.taskHistory.push({
            task: currentTask,
            result,
            timestamp: Date.now(),
          });
        } catch (e) {
          console.error(`Error executing task ${currentTask.id}:`, e);
        }
      } else {
        console.error(`Unknown function name for task ${currentTask.id}: ${currentTask.functionName}`);
      }
    }

    // Use a non-recursive setTimeout to prevent stack depth issues and memory leaks
    if (this.running) {
      this.pollTimeout = setTimeout(() => this.poll(), this.fetchIntervalMs);
    }
  }
}
