    jest.useRealTimers();
  });

  it('should not execute tasks before start() is called', () => {
    const poller = new TaskPoller(100);
    const mockTask: Task = { id: '1', script: 'global.taskExecuted = true' };

    // A way to observe the side-effect of eval
    (global as any).taskExecuted = false;

    poller.addTask(mockTask);
    jest.advanceTimersByTime(200);

    expect((global as any).taskExecuted).toBe(false);
  });

  it('should execute a task after start() is called and interval passes', () => {
    const poller = new TaskPoller(100);
    const mockTask: Task = { id: '1', script: 'global.taskExecuted = true' };
    (global as any).taskExecuted = false;

    poller.start();
    poller.addTask(mockTask);

    // Advance time by one interval
    jest.advanceTimersByTime(100);

    expect((global as any).taskExecuted).toBe(true);
  });

  it('should stop executing tasks after stop() is called', () => {
    const poller = new TaskPoller(100);
    const mockTask1: Task = { id: '1', script: 'global.taskCount = (global.taskCount || 0) + 1' };
    const mockTask2: Task = { id: '2', script: 'global.taskCount = (global.taskCount || 0) + 1' };
    (global as any).taskCount = 0;

    poller.start();
    poller.addTask(mockTask1);
    poller.addTask(mockTask2);

    // Execute the first task
    jest.advanceTimersByTime(100);
    expect((global as any).taskCount).toBe(1);

    poller.stop();

    // Advance time again; the second task should not run
    jest.advanceTimersByTime(100);
    expect((global as any).taskCount).toBe(1);
  });

  it('should process tasks in FIFO order', () => {
    const poller = new TaskPoller(100);
    const executionOrder: string[] = [];
    const mockTask1: Task = { id: '1', script: 'executionOrder.push("1")' };
    const mockTask2: Task = { id: '2', script: 'executionOrder.push("2")' };

    // Make the executionOrder array available in the "eval" scope
    (global as any).executionOrder = executionOrder;

    poller.start();
    poller.addTask(mockTask1);
    poller.addTask(mockTask2);

    jest.advanceTimersByTime(100);
    expect(executionOrder).toEqual(['1']);

    jest.advanceTimersByTime(100);
    expect(executionOrder).toEqual(['1', '2']);

    delete (global as any).executionOrder;
  });

  it('should continue polling even if a task throws an error', () => {
    // Suppress console.error for this test
    const consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation(() => {});

    const poller = new TaskPoller(100);
    const errorTask: Task = { id: 'error-task', script: 'throw new Error("test error")' };
    const successTask: Task = { id: 'success-task', script: 'global.successTaskExecuted = true' };
    (global as any).successTaskExecuted = false;

    poller.start();
    poller.addTask(errorTask);
    poller.addTask(successTask);

    // Process the error task
    jest.advanceTimersByTime(100);
    expect(consoleErrorSpy).toHaveBeenCalledWith('Error executing task error-task:', expect.any(Error));

    // Process the success task
    jest.advanceTimersByTime(100);
    expect((global as any).successTaskExecuted).toBe(true);

    consoleErrorSpy.mockRestore();
  });
});
